INSERT INTO `articulos` (`id`, `empresa_id`, `sku`, `titulo`, `descripcion`, `precio`, `unidad`, `activo`, `created_at`, `updated_at`, `orden`) VALUES
(2, 2, NULL, 'CLOSET MELAMINA STANDARD', 'Closet en Melamina 👗👔👜 Catálogo Standard. Incluye:\n✅Closet Empotrado.\n✅Torre Cajonera de 5 cajones ancho máximo 60 cms.\n✅Puertas Principales ancho máximo 60 cms.\n✅Puertas en Maletero ancho máximo 60 cms.\n✅Closet Profundidad Standard 62 cms máximo.\n✅Altura máxima 270 cms.\n✅Bisagras Reforzadas, Tubos y Jaladera estilo Contemporaneo.\n✅Base y Zoclo (no se ve el piso).\n✅No incluye forro de muros.', 1.00, NULL, 1, '2026-03-17 11:48:15', '2026-03-17 11:48:15', 0),
(3, 2, NULL, 'CLOSET MELAMINA WALK IN VESTIDOR', 'FRENTES, PUERTAS EN MALETERO\nUNA TORRE CON HASTA 5 CAJONES, PUERTA COSMETIQUERA Y REPISA INTERIOR. \nKIT DE HERRAJES Y BISAGRAS BIDIRECCIONALES, RIELES DE EXTENSION 18\" REFORZADOS, JALADERAS DE NUESTRO CATALOGO.\nPROFUNDIDAD STANDARD 60 CMS APROX. \nCAJON ADICIONAL $450. REPISAS O DISEÑO ADICIONALES, TORRES ADICIONALES, \nNO INCLUYE FORRO DE AREA DE PARED, SE COBRAN POR SEPARADO.', 1.00, NULL, 1, '2026-03-17 11:49:12', '2026-03-17 11:49:12', 0),
(4, 2, NULL, 'CLOSET MELAMINA WALK IN VESTIDOR SIN PUERTAS', 'FRENTES, BASES Y CARGADORES. (SIN PUERTAS EN MALETERO)\nUNA TORRE CON HASTA 5 CAJONES, PUERTA COSMETIQUERA Y REPISA INTERIOR. \nKIT DE HERRAJES Y BISAGRAS BIDIRECCIONALES, RIELES DE EXTENSION 18\" REFORZADOS, JALADERAS DE NUESTRO CATALOGO. \nPROFUNDIDAD STANDARD 60 CMS APROX. \nCAJON ADICIONAL $450. REPISAS O DISEÑO ADICIONALES, TORRES ADICIONALES, \nNO INCLUYE FORRO DE AREA DE PARED, SE COBRAN POR SEPARADO.', 1.00, NULL, 1, '2026-03-17 11:49:53', '2026-03-17 11:49:53', 0);
